```csharp
using System;
using System.Reflection;
using System.Linq;
using Microsoft.EntityFrameworkCore;

public abstract class BaseRepository<T> : IBaseRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual IQueryable<T> FindByDynamicField(string fieldName, object value)
    {
        var propertyInfo = typeof(T).GetProperty(fieldName);

        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property {fieldName} does not exist in {typeof(T).Name}");
        }

        return _dbSet.Where(x => propertyInfo.GetValue(x).Equals(value));
    }

    // Other methods...
}
```

